    private int[] buffer;
    private int front, rear, capacity;

    public MyCircularDeque(int k) {
        buffer = new int[k];
        front = -1;
        rear = 0;
        capacity = k;
    }

    public boolean insertFront(int value) {
        if (isFull()) {
            return false;
        }
        if (front == -1) {
            front = 0;
        } else {
            front = (front - 1 + capacity) % capacity;
        }
        buffer[front] = value;
        return true;
    }

    public boolean insertLast(int value) {
        if (isFull()) {
            return false;
        }
        buffer[rear] = value;
        rear = (rear + 1) % capacity;
        if (front == -1) {
            front = 0;
        }
        return true;
    }

    public boolean deleteFront() {
        if (isEmpty()) {
            return false;
        }
        if (front == rear - 1) {
            front = -1;
        } else {
            front = (front + 1) % capacity;
        }
        return true;
    }

    public boolean deleteLast() {
        if (isEmpty()) {
            return false;
        }
        if (front == rear - 1) {
            rear = 0;
            front = -1;
        } else {
            rear = (rear - 1 + capacity) % capacity;
        }
        return true;
    }

    public int getFront() {
        if (isEmpty()) {
            return -1;
        }
        return buffer[front];
    }

    public int getRear() {
        if (isEmpty()) {
            return -1;
        }
        return buffer[(rear - 1 + capacity) % capacity];
    }

    public boolean isEmpty() {
        return front == -1;
    }

    public boolean isFull() {
        return front == rear;
    }
}
